    TQue<TPosition::VECIN, BUFFER_NUM> inQueuePatch_;
    TQue<TPosition::VECIN, BUFFER_NUM> inQueueWeight_;
    TQue<TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    TQue<TPosition::VECCALC, 1> tmpQueue_;

    GlobalTensor<float> xGm_;
